    hk_per_key, hk_map_meta, gb_totaal, gsl_key, hk_pc_map = get_hk_meta()
    ink_per_key, ink_col_inw, ink_col_ontv, ink_col_med, ink_pc_to_regio, ink_nl_key = get_ink_cols_en_periode()

